1	'use strict';
2	/**
3	 * breach/verifiers/coverage-proof.js - verifies a `coverage_proof` artifact: the artifact class for
4	 * ABSENCE claims ("no complaints procedure was found", "no cookie banner present"). Constitution
5	 * Rule 3 lists a verbatim quote, a network event and a register row as artifacts for something
6	 * PRESENT; an absence claim has no quote to point at by definition, so its deterministic artifact is
7	 * proof that the relevant surface was actually, sufficiently crawled (caution.md C-029: coverage as
8	 * BLOCKING data, not reporting theatre; C-037: every fabrication-prone absence is gated behind a real
9	 * live-read guard).
10	 *
11	 * Contract (candidate.artifact when type === 'coverage_proof'):
12	 *   {
13	 *     type: 'coverage_proof',
14	 *     page_class,           // informational: which page-class the absence claim concerns
15	 *     coverage: {
16	 *       pages: [url, ...],   // the pages examined for this class; MUST be non-empty
17	 *       tier1_fetched,       // true only if Tier-1 legal pages were fetched before any cap (C-026)
18	 *       truncated,           // must be false: a truncated corpus cannot honestly ground an absence
19	 *                            // claim (C-024/C-025 - russell-cooke's SRA string sat at char 11,080)
20	 *     },
21	 *   }
22	 *
23	 * This module never re-derives the coverage computation itself (that stays evidence/crawler/
24	 * coverage-contract.js's one door): it checks structural presence and cross-checks the claimed pages
25	 * against bundle.corpus.pages, so a coverage_proof cannot invent pages nobody actually crawled.
26	 */
27	const { CODES, accepted, rejected } = require('./result');
28	
29	// bundlePageUrlSet(bundle) -> the Set of page URLs actually present on the bundle's corpus. Empty
30	// when the bundle carries no corpus at all (an unreachable/bot-walled bundle, caution.md C-038).
31	function bundlePageUrlSet(bundle) {
32	  const pages = bundle && bundle.corpus && Array.isArray(bundle.corpus.pages) ? bundle.corpus.pages : [];
33	  return new Set(pages.map((p) => p && p.url));
34	}
35	
36	// verifyCoverageProof(artifact, bundle) -> {verified, code, reason}. Fails closed on: a missing
37	// coverage object, an empty/absent pages list, a claimed page not actually present in the bundle's
38	// corpus, tier1_fetched not literally true, or truncated not literally false.
39	function verifyCoverageProof(artifact, bundle) {
40	  const coverage = artifact.coverage;
41	  if (!coverage || typeof coverage !== 'object') {
42	    return rejected(CODES.COVERAGE_PROOF_MISSING_FIELDS, 'artifact.coverage is required');
43	  }
44	  if (!Array.isArray(coverage.pages) || coverage.pages.length === 0) {
45	    return rejected(CODES.COVERAGE_PROOF_NO_PAGES, 'artifact.coverage.pages must be a non-empty list of crawled page URLs');
46	  }
47	  const provenUrls = bundlePageUrlSet(bundle);
48	  const unproven = coverage.pages.filter((url) => !provenUrls.has(url));
49	  if (unproven.length > 0) {
50	    return rejected(
51	      CODES.COVERAGE_PROOF_PAGES_NOT_IN_BUNDLE,
52	      'coverage.pages lists page(s) absent from bundle.corpus.pages: ' + unproven.join(', ')
53	    );
54	  }
55	  if (coverage.tier1_fetched !== true) {
56	    return rejected(
57	      CODES.COVERAGE_PROOF_TIER1_NOT_FETCHED,
58	      'coverage.tier1_fetched must be true (C-026: Tier-1 legal pages fetched before any commercial page or cap)'
59	    );
60	  }
61	  if (coverage.truncated !== false) {
62	    return rejected(
63	      CODES.COVERAGE_PROOF_TRUNCATED,
64	      'coverage.truncated must be false (C-024/C-025: an absence claim on a truncated corpus is not provable)'
65	    );
66	  }
67	  return accepted(
68	    CODES.COVERAGE_PROOF_VERIFIED,
69	    'coverage report proves the surface was crawled: ' + coverage.pages.length + ' page(s), Tier-1 fetched, not truncated'
70	  );
71	}
72	
73	module.exports = { verifyCoverageProof, bundlePageUrlSet };
