1	'use strict';
2	/**
3	 * propose.js - the breach PROPOSER (P3 Wave-2a). The ONLY producer of breach CANDIDATES.
4	 *
5	 * propose(bundle, catalogue, coverage) -> candidates[]. It compiles the catalogue's prose obligations
6	 * into DetectionSpecs (detection-spec.js), then evaluates each against the pure EvidenceBundle and the
7	 * per-rule coverage verdict. A proposer PROPOSES; it NEVER emits a finding (Constitution: propose ->
8	 * verify -> adjudicate; C-079). Every candidate it emits carries a deterministic artifact (Rule 3): a
9	 * verbatim quote string-matched to the corpus, a captured browser event, a definitive register-lane
10	 * fact, or a coverage proof. No artifact, no candidate.
11	 *
12	 * ── how each evidence_type routes ────────────────────────────────────────────────────────────────
13	 *   presence   (REQUIRED content)  -> ABSENCE-breach: the required pattern is ABSENT across the covered,
14	 *                                     declared surface. Fires only with the coverage interlock proven
15	 *                                     (record covered, corpus not truncated, >= the min-pages floor,
16	 *                                     surface readable). Artifact: coverage_proof. confidence: moderate.
17	 *   absence    (PROHIBITED content)-> PRESENCE-breach: the prohibited pattern is FOUND inside one visible
18	 *                                     prose sentence that is neither negated (the site's own compliant
19	 *                                     self-declaration, C-048) nor a customer review (C-090). Artifact:
20	 *                                     the verbatim quote. confidence: strong.
21	 *   behavioural                    -> consume bundle.browser.observed (C-039 pre-consent cookie set as a
22	 *                                     completed observed breach; C-042 broken consent control). Artifact:
23	 *                                     the captured network/observation event. confidence: strong.
24	 *   register                       -> consume bundle.registers: a DEFINITIVE no-match note for the
25	 *                                     record's register (C-004) is a candidate; a present row is
26	 *                                     compliant (no candidate); a degraded lane suppresses. confidence:
27	 *                                     weak (a no-match is not proof of non-registration; the adjudicator
28	 *                                     quarantines it, Rule 6).
29	 *
30	 * ── suppression is FIRST-CLASS and VISIBLE (C-029/C-024/C-026/C-037/C-041) ────────────────────────
31	 * A would-be candidate withheld by an evidence-quality gate is returned as a candidate carrying
32	 * suppressed_reason and a null artifact, so the abstention is recorded, never silent. A rule whose
33	 * page-class coverage is 'screened' NEVER proposes (C-029). A clean non-breach (prohibited content
34	 * simply absent, or required content present, or a matched register row) returns NOTHING - only real
35	 * breach signals and real evidence-quality abstentions appear in the output.
36	 *
37	 * Pure and synchronous over the bundle: no network, no clock, no env. Holds NO law/fine/regulator
38	 * literal (Rule 2); every word it scans for is compiled from the catalogue argument at runtime.
39	 */
40	const spec = require('./detection-spec.js');
41	const coverageContract = require('../../evidence/crawler/coverage-contract.js');
42	
43	// MIN_PAGES_FOR_ABSENCE: the code-clamped floor for any absence claim (C-025: a safety floor lives in
44	// code and cannot be forced below itself; matches facts/capabilities.js's own MIN_PAGES_FOR_ABSENCE).
45	const MIN_PAGES_FOR_ABSENCE = 3;
46	
47	const KIND = Object.freeze({
48	  PRESENCE_BREACH: 'presence-breach',   // prohibited content FOUND (from an 'absence' obligation)
49	  ABSENCE_BREACH: 'absence-breach',     // required content MISSING (from a 'presence' obligation)
50	  BEHAVIOURAL: 'behavioural',
51	  REGISTER: 'register',
52	});
53	
54	// Generic web-behaviour concepts an observed browser event implies (Rule 2 safe: no law/regulator name).
55	// A behavioural obligation only consumes an observation when the obligation's own tokens intersect the
56	// concept set for that observation kind, so a non-consent behavioural duty never claims the cookie event.
57	const OBSERVATION_CONCEPTS = Object.freeze({
58	  cookie_pre_consent: ['cookie', 'cookies', 'consent', 'tracking', 'tracker', 'marketing', 'analytics'],
59	  consent_control_broken: ['cookie', 'cookies', 'consent', 'banner', 'preferences'],
60	});
61	
62	// ── bundle readers (tolerant; the pure EvidenceBundle shape from facts/README.md) ─────────────────
63	function pagesOf(bundle) {
64	  const pages = bundle && bundle.corpus && Array.isArray(bundle.corpus.pages) ? bundle.corpus.pages : [];
65	  return pages.filter((p) => p && typeof p.text === 'string');
66	}
67	function footerOf(bundle) {
68	  return bundle && bundle.corpus && typeof bundle.corpus.footerText === 'string' ? bundle.corpus.footerText : '';
69	}
70	// isTruncated(bundle): the crawler flags a page past the corpus cap (C-024). Read defensively from the
71	// spots the crawl telemetry may surface it on; a missing flag is treated as NOT truncated, and that
72	// dependency on the bundle assembler propagating truncation is flagged honestly to the caller.
73	function isTruncated(bundle) {
74	  if (!bundle) return false;
75	  if (bundle.corpus && typeof bundle.corpus.truncated === 'boolean') return bundle.corpus.truncated;
76	  if (typeof bundle.truncated === 'boolean') return bundle.truncated;
77	  return Boolean(bundle.telemetry && bundle.telemetry.truncated);
78	}
79	// isUnreadable(bundle): a bot-walled or SPA-shell bundle carries no readable page (C-038). Nothing is
80	// ever asserted about content that was not read; propose returns [] on it.
81	function isUnreadable(bundle) {
82	  return pagesOf(bundle).length === 0;
83	}
84	// isNonEnglishGated(bundle): the facts layer gates a non-English corpus to compliance_unassessed before
85	// any rule runs (C-022). If the bundle carries that gate, propose asserts nothing.
86	function isNonEnglishGated(bundle) {
87	  if (!bundle) return false;
88	  if (bundle.compliance_unassessed === true) return true;
89	  const lang = bundle.corpus && bundle.corpus.language;
90	  return typeof lang === 'string' && lang !== '' && !/^en\b/i.test(lang);
91	}
92	
93	// coverageStateFor(coverage, recordId) -> 'covered' | 'screened' | 'unknown'. 'unknown' (the record is
94	// absent from the coverage report) is treated fail-closed as no-coverage-proof by the absence interlock.
95	function coverageStateFor(coverage, recordId) {
96	  const rules = coverage && Array.isArray(coverage.rules) ? coverage.rules : null;
97	  if (!rules) return 'unknown';
98	  const row = rules.find((r) => r && r.id === recordId);
99	  return row ? row.state : 'unknown';
100	}
101	
102	// ── surface selection ─────────────────────────────────────────────────────────────────────────────
103	// pagesOfClass(pages, pageClass) -> the pages whose path classifies to pageClass; all pages for 'any'.
104	// Uses coverage-contract.classify (anchored path segments, never substrings - C-044), the one door for
105	// page-class so the surface propose scans matches the surface coverage judged (C-035).
106	function pagesOfClass(pages, pageClass) {
107	  if (!pageClass || pageClass === 'any') return pages;
108	  return pages.filter((p) => coverageContract.classify(p.url) === pageClass);
109	}
110	// surfaceTextForPresence(spec, pages, footer) -> the surface text a REQUIRED-content check scans, plus
111	// the pages it covers. The footer is ALWAYS included, never scanned exclusively: it is an ADDITIONAL
112	// mandatory statutory-disclosure surface (C-034), so a disclosure in the body OR the footer counts as
113	// present. Scanning the footer alone would read a body disclosure as "missing" (the false-positive this
114	// fixes). 'raw_html' is unreadable in the stripped bundle; the interlock abstains before reaching here.
115	function surfaceTextForPresence(detectionSpec, pages, footer) {
116	  const scoped = pagesOfClass(pages, detectionSpec.page_class);
117	  const text = scoped.map((p) => p.text).concat(footer ? [footer] : []).join('\n');
118	  const coveredPages = scoped.map((p) => p.url).concat(footer ? ['(footer)'] : []);
119	  return { text, coveredPages };
120	}
121	
122	// ── pattern matching ───────────────────────────────────────────────────────────────────────────────
123	// pathHasSegment(url, seg) -> true when the url path contains seg ('/xxx') as a WHOLE segment (anchored,
124	// never a substring - C-044). matchUrlPath scans every page for the url-path pattern.
125	function pathHasSegment(url, seg) {
126	  let path;
127	  try { path = new URL(url).pathname.toLowerCase(); }
128	  catch (_err) {
129	    // FAIL-OPEN: a non-URL is matched as a raw path, never crashes the scan.
130	    path = String(url || '').toLowerCase();
131	  }
132	  const norm = ('/' + path.replace(/^\/+/, '')).replace(/\/+$/, '') + '/';
133	  return norm.includes(seg.toLowerCase() + '/') || norm.includes(seg.toLowerCase() + '-');
134	}
135	function matchUrlPath(value, pages) {
136	  return pages.some((p) => pathHasSegment(p.url, value));
137	}
138	// patternMatchesText(pattern, text) -> does a text pattern (anchored-regex or token-set) match `text`.
139	function patternMatchesText(pattern, text) {
140	  const re = spec.compileRegex(pattern);
141	  return re ? re.test(text) : false;
142	}
143	// requiredContentPresent(detectionSpec, surfaceText, pages) -> is ANY pattern satisfied (the lenient
144	// "present" check for a REQUIRED disclosure: a partial or differently-worded disclosure still counts as
145	// present, so the absence-breach fires only on total silence - the C-024 false-missing guard).
146	function requiredContentPresent(detectionSpec, surfaceText, pages) {
147	  for (const pattern of detectionSpec.patterns) {
148	    if (pattern.kind === 'url-path') { if (matchUrlPath(pattern.value, pages)) return true; continue; }
149	    if (patternMatchesText(pattern, surfaceText)) return true;
150	  }
151	  return false;
152	}
153	// prohibitedHitInSentence(detectionSpec, sentence) -> the first pattern that matches WHOLLY within one
154	// sentence (a scattered token-set across the page is not a single prohibited claim), or null.
155	function prohibitedHitInSentence(detectionSpec, sentence) {
156	  for (const pattern of detectionSpec.patterns) {
157	    if (pattern.kind === 'url-path') continue;
158	    if (patternMatchesText(pattern, sentence)) return pattern;
159	  }
160	  return null;
161	}
162	
163	// findProhibitedQuote(detectionSpec, pages) -> { page_url, quote, guardedOnly }. Scans visible prose
164	// sentence by sentence; a carrier sentence must be genuine prose (C-089), not negated (C-048) and not a
165	// customer review (C-090). guardedOnly signals a match existed but every carrier was guarded away (a
166	// compliant self-declaration), so the abstention can be recorded rather than silent.
167	function findProhibitedQuote(detectionSpec, pages) {
168	  let sawGuarded = false;
169	  for (const page of pages) {
170	    for (const sentence of spec.splitSentences(page.text)) {
171	      if (!prohibitedHitInSentence(detectionSpec, sentence)) continue;
172	      if (spec.isNegated(sentence) || spec.looksLikeReview(sentence)) { sawGuarded = true; continue; }
173	      if (!spec.isProse(sentence)) continue;
174	      return { page_url: page.url, quote: sentence, guardedOnly: false };
175	    }
176	  }
177	  return { page_url: null, quote: null, guardedOnly: sawGuarded };
178	}
179	
180	// ── candidate builders ─────────────────────────────────────────────────────────────────────────────
181	function candidate(detectionSpec, kind, artifact, pageUrl, confidence) {
182	  return {
183	    record_id: detectionSpec.record_id,
184	    duty_idx: detectionSpec.duty_idx,
185	    evidence_type: detectionSpec.evidence_type,
186	    kind,
187	    artifact,
188	    page_url: pageUrl,
189	    confidence_hint: confidence,
190	    suppressed_reason: null,
191	  };
192	}
193	function suppressed(detectionSpec, kind, reason) {
194	  return {
195	    record_id: detectionSpec.record_id,
196	    duty_idx: detectionSpec.duty_idx,
197	    evidence_type: detectionSpec.evidence_type,
198	    kind,
199	    artifact: null,
200	    page_url: null,
201	    confidence_hint: null,
202	    suppressed_reason: reason,
203	  };
204	}
205	
206	// ── evaluators (one per evidence_type; each returns a candidate, a suppressed record, or null) ──────
207	
208	// evalPresenceBreach: an 'absence' obligation (PROHIBITED content). A hit in a clean visible sentence is
209	// a presence-breach with the verbatim quote as artifact (confidence strong). If every hit was negated /
210	// a review, record the abstention. No hit -> clean pass (null).
211	function evalPresenceBreach(detectionSpec, pages) {
212	  if (!detectionSpec.patterns.length) return null;
213	  const found = findProhibitedQuote(detectionSpec, pages);
214	  if (found.quote) {
215	    const artifact = { type: 'quote', text: found.quote, surface: detectionSpec.surface };
216	    return candidate(detectionSpec, KIND.PRESENCE_BREACH, artifact, found.page_url, 'strong');
217	  }
218	  if (found.guardedOnly) return suppressed(detectionSpec, KIND.PRESENCE_BREACH, 'all-matches-negated-or-review (compliant self-declaration or testimonial, C-048/C-090)');
219	  return null;
220	}
221	
222	// absenceInterlock(detectionSpec, bundle, coverageState) -> a suppression reason, or null when the
223	// coverage interlock is fully satisfied (C-024/C-025/C-026/C-036). Fail-closed: any doubt suppresses.
224	function absenceInterlock(detectionSpec, bundle, coverageState) {
225	  if (coverageState !== 'covered') return 'coverage ' + coverageState + ' for this rule; an absence claim needs a proven page-class (C-029)';
226	  if (detectionSpec.surface === 'raw_html') return 'required mechanism lives in raw HTML, unreadable in the stripped corpus; abstained rather than fabricate a missing-mechanism breach (C-036/C-032)';
227	  if (detectionSpec.surface === 'footer' && !footerOf(bundle)) return 'no footer surface was captured; a registration-disclosure absence cannot be asserted (C-034)';
228	  if (pagesOf(bundle).length < MIN_PAGES_FOR_ABSENCE) return 'corpus below the ' + MIN_PAGES_FOR_ABSENCE + '-page floor for an absence claim (C-025)';
229	  if (isTruncated(bundle)) return 'corpus was truncated; the required content may sit past the cut, so the absence claim is demoted (C-024)';
230	  return null;
231	}
232	
233	// evalAbsenceBreach: a 'presence' obligation (REQUIRED content). If the content is present -> clean pass.
234	// If absent, the interlock decides: satisfied -> an absence-breach with a coverage_proof artifact
235	// (confidence moderate); unsatisfied -> a recorded suppression.
236	function evalAbsenceBreach(detectionSpec, bundle, coverageState) {
237	  if (!detectionSpec.patterns.length) return null;
238	  const pages = pagesOf(bundle);
239	  const surface = surfaceTextForPresence(detectionSpec, pages, footerOf(bundle));
240	  if (requiredContentPresent(detectionSpec, surface.text, pages)) return null; // present -> no breach
241	  const block = absenceInterlock(detectionSpec, bundle, coverageState);
242	  if (block) return suppressed(detectionSpec, KIND.ABSENCE_BREACH, block);
243	  const artifact = {
244	    type: 'coverage_proof',
245	    page_class: detectionSpec.page_class,
246	    surface: detectionSpec.surface,
247	    pages_checked: surface.coveredPages,
248	    searched_patterns: detectionSpec.patterns.map(patternSummary),
249	  };
250	  return candidate(detectionSpec, KIND.ABSENCE_BREACH, artifact, null, 'moderate');
251	}
252	function patternSummary(pattern) {
253	  if (pattern.kind === 'token-set') return { kind: pattern.kind, tokens: pattern.value.tokens, mode: pattern.value.mode };
254	  return { kind: pattern.kind, value: pattern.value };
255	}
256	
257	// specTokens(detectionSpec) -> the flat set of lane-routing tokens a behavioural/register spec carries.
258	function specTokens(detectionSpec) {
259	  const out = new Set();
260	  for (const p of detectionSpec.patterns) {
261	    if (p.kind === 'token-set') for (const t of p.value.tokens) out.add(String(t).toLowerCase());
262	  }
263	  return out;
264	}
265	// obligationConcerns(detectionSpec, obsKind) -> does this behavioural obligation concern an observation
266	// of this kind (token intersection with the generic concept set); gates C-039/C-042 to consent duties.
267	function obligationConcerns(detectionSpec, obsKind) {
268	  const concepts = OBSERVATION_CONCEPTS[obsKind] || [];
269	  const tokens = specTokens(detectionSpec);
270	  return concepts.some((c) => tokens.has(c) || [...tokens].some((t) => t.includes(c)));
271	}
272	
273	// laneRan(browser) -> true only when the browser lane definitively ran; laneReason gives the recorded
274	// non-run reason (C-041: an evidence lane's absence is visible, never silent).
275	function laneRan(browser) {
276	  return Boolean(browser && browser.lane && browser.lane.ran === true);
277	}
278	function laneReason(browser) {
279	  return (browser && browser.lane && browser.lane.reason) || 'browser lane did not run';
280	}
281	// observedCandidates(detectionSpec, observed) -> a behavioural candidate per observation this obligation
282	// concerns (C-039: a pre-consent cookie set is a completed observed breach with the event as artifact).
283	function observedCandidates(detectionSpec, observed) {
284	  const out = [];
285	  for (const ev of (Array.isArray(observed) ? observed : [])) {
286	    if (!ev || !ev.kind || !obligationConcerns(detectionSpec, ev.kind)) continue;
287	    out.push(candidate(detectionSpec, KIND.BEHAVIOURAL, { type: 'network_event', ...ev }, ev.host || ev.url || null, 'strong'));
288	  }
289	  return out;
290	}
291	// brokenControlCandidate(detectionSpec, cc) -> a behavioural candidate when a found consent control is
292	// unhealthy on a consent-concerned obligation (C-042: a broken control is itself a finding class), else null.
293	function brokenControlCandidate(detectionSpec, cc) {
294	  if (!cc || cc.found !== true || cc.healthy !== false) return null;
295	  if (!obligationConcerns(detectionSpec, 'consent_control_broken')) return null;
296	  const artifact = { type: 'network_event', kind: 'consent_control_broken', url: cc.url || null, healthy: false };
297	  return candidate(detectionSpec, KIND.BEHAVIOURAL, artifact, cc.url || null, 'strong');
298	}
299	// evalBehavioural: consume bundle.browser. The lane not running is a recorded suppression (C-041).
300	function evalBehavioural(detectionSpec, bundle) {
301	  const browser = bundle && bundle.browser;
302	  if (!laneRan(browser)) return [suppressed(detectionSpec, KIND.BEHAVIOURAL, 'browser lane unavailable: ' + laneReason(browser) + ' (C-041)')];
303	  const out = observedCandidates(detectionSpec, browser.observed);
304	  const broken = brokenControlCandidate(detectionSpec, browser.consentControl);
305	  if (broken) out.push(broken);
306	  return out;
307	}
308	
309	// registerTargetFor(detectionSpec, record, keys) -> the bundle register key this record's register duty
310	// checks, derived from the record's OWN id/citation/register_url tokens against the bundle's OWN register
311	// keys (data-driven; no regulator name is authored here - Rule 2), or null when unresolved.
312	function registerTargetFor(record, keys) {
313	  const blob = [record && record.id, record && record.regulator && record.regulator.register_url,
314	    record && record.citation && record.citation.url].filter(Boolean).join(' ').toLowerCase();
315	  return keys.find((k) => blob.includes(String(k).toLowerCase())) || null;
316	}
317	// evalRegister: consume bundle.registers. A present matched row is compliant (no candidate). A DEFINITIVE
318	// no_match note (C-004) is a weak candidate carrying that note as its register_row artifact. Any other
319	// state (no target resolvable, a degraded/skipped lane, no note at all) is a recorded suppression.
320	function evalRegister(detectionSpec, bundle, record) {
321	  const registers = (bundle && bundle.registers) || {};
322	  const keys = Object.keys(registers).filter((k) => k !== 'notes');
323	  const notes = Array.isArray(registers.notes) ? registers.notes : [];
324	  const noteKeys = notes.map((n) => n && n.register).filter(Boolean);
325	  const target = registerTargetFor(record, [...new Set([...keys, ...noteKeys])]);
326	  if (!target) return suppressed(detectionSpec, KIND.REGISTER, 'no register lane resolvable for this record (unregistered lane / no lookup)');
327	  if (registers[target]) return null; // a matched row is present -> compliant on this duty
328	  const note = notes.find((n) => n && n.register === target);
329	  if (note && note.kind === 'no_match') {
330	    return candidate(detectionSpec, KIND.REGISTER, { type: 'register_row', present: false, register: target, lane: 'no_match', note }, null, 'weak');
331	  }
332	  return suppressed(detectionSpec, KIND.REGISTER, 'register "' + target + '" not definitively checked (' + ((note && note.kind) || 'no note') + '); a no-match is required before a non-appearance claim (C-004)');
333	}
334	
335	// ── the router ──────────────────────────────────────────────────────────────────────────────────────
336	function recordsForIndex(catalogue) {
337	  if (Array.isArray(catalogue)) return catalogue;
338	  if (catalogue && Array.isArray(catalogue.records)) return catalogue.records;
339	  return [];
340	}
341	function recordIndex(catalogue) {
342	  const map = new Map();
343	  for (const r of recordsForIndex(catalogue)) if (r && r.id) map.set(r.id, r);
344	  return map;
345	}
346	
347	// evaluateSpec(detectionSpec, bundle, coverage, record) -> candidate[] for one spec (0..n). Exported for
348	// unit tests. A page-class-bearing spec whose coverage is 'screened' NEVER proposes (C-029), the hard
349	// block applied before any evidence is read.
350	function evaluateSpec(detectionSpec, bundle, coverage, record) {
351	  const coverageState = coverageStateFor(coverage, detectionSpec.record_id);
352	  if (detectionSpec.page_class !== null && coverageState === 'screened') {
353	    return [suppressed(detectionSpec, kindForType(detectionSpec.evidence_type), 'page-class coverage screened; a screened rule never proposes (C-029)')];
