371	  adjudicate,
372	  // exported for the node:test suite + the calibration fixtures (helpers, never fact producers):
373	  classifyAll,
374	  ctxFromBundle,
375	  evidenceText,
376	  briefOf,
377	  systemPrompt,
378	  buildPrompt,
379	  rubricFor,
380	  verdictsFrom,
381	  applyVerdicts,
382	  BATCH,
383	  DEFAULT_DEADLINE_MS,
