34	// verdictWord(raw) -> the lowercased verdict string carried by a raw verdict (a { verdict } object or
35	// a bare string), or null when none is present. Non-string verdict fields are null (a wrong type is
36	// not a verdict).
37	function verdictWord(raw) {
