98	  }
99	  if (v === 'insufficient') {
100	    return abstain('insufficient', reasonOf(raw, 'insufficient evidence to rule either way -> abstain'));
101	  }
102	  // v === 'no_breach': clears to pass ONLY with a verbatim disproof anchored in the evidence (C-092).
103	  const disproof = raw && raw.disproof;
