105	    return { state: 'pass', verdict: 'no_breach', reason: reasonOf(raw, 'false positive, disproved verbatim'), disproof: normaliseDisproof(disproof) };
106	  }
107	  return abstain('no_breach', 'no_breach with no verbatim disproof anchored in the evidence (C-092) -> abstain');
108	}
109	
110	module.exports = {
111	  parseVerdict,
112	  normaliseVerdict,
113	  disproofMatches,
114	  normaliseDisproof,
115	  LLM_VERDICTS,
116	  STATES,
117	  VERDICT_TO_STATE,
118	  MIN_DISPROOF_CHARS,
119	  DISPROOF_ANCHOR_CHARS,
120	};
