98	  let hasAbsence = false;
99	  for (const o of obligations) {
100	    const cls = pageClassForObligation(o);
101	    if (cls) needs.add(cls);
102	    if (o && o.evidence_type === 'absence') hasAbsence = true;
103	  }
104	  return { needs: [...needs], laneOnly: needs.size === 0, hasAbsence };
