358	    unpatternable_elements: unpatternable,
359	  };
360	}
361	
362	// compileRecordSpecs(record) -> the DetectionSpec[] for one record's website_obligations[].
363	function compileRecordSpecs(record) {
364	  const obligations = (record && Array.isArray(record.website_obligations)) ? record.website_obligations : [];
365	  const specs = [];
366	  for (let i = 0; i < obligations.length; i++) {
367	    const spec = specForObligation(record, obligations[i], i);
368	    if (spec) specs.push(spec);
369	  }
370	  return specs;
371	}
372	
373	// recordsOf(catalogue) -> the records array from a compiled catalogue artifact ({records:[...]}) or a
374	// bare array; anything else is []. Tolerant so a caller may pass either shape.
375	function recordsOf(catalogue) {
376	  if (Array.isArray(catalogue)) return catalogue;
377	  if (catalogue && Array.isArray(catalogue.records)) return catalogue.records;
378	  return [];
379	}
380	
381	// compileCatalogue(catalogue) -> { specs, rejected }. Every obligation of every record becomes a spec;
382	// each spec is validated at the source (C-009/C-019), and any spec carrying an unanchored/bare pattern
383	// is REJECTED here with its reasons rather than shipped - an unanchored pattern is unrepresentable in
384	// what propose.js consumes.
385	function compileCatalogue(catalogue) {
386	  const specs = [];
387	  const rejected = [];
388	  for (const record of recordsOf(catalogue)) {
389	    for (const spec of compileRecordSpecs(record)) {
390	      const v = validateSpec(spec);
391	      if (v.valid) specs.push(spec);
392	      else rejected.push({ record_id: spec.record_id, duty_idx: spec.duty_idx, errors: v.errors });
393	    }
394	  }
395	  return { specs, rejected };
396	}
397	
398	// ── validation (the C-009/C-019 anchoring gate; the p3-proposer-unanchored-pattern fixture drives it) ──
399	// isAnchoredPatternValue(pattern) -> { ok, reason }. A pattern is REJECTED when it is bare/unanchored:
400	//   - anchored-regex: source must contain a \b word boundary or a ^/$ anchor AND must compile; a bare
401	//     alternation like "EU" or a bare substring like "cost" (no \b, no ^/$) is rejected (C-019/C-044/C-059).
402	//   - token-set: non-empty; every token >= MIN_TOKEN_LEN and a clean word (a 1-2 char or punctuation
403	//     token would substring-match, the "post"->postcode class C-059).
404	//   - url-path: a rooted single path segment ('/xxx'), never a bare word (the /cost-of-living class C-044).
405	function isAnchoredPatternValue(pattern) {
406	  if (!pattern || typeof pattern !== 'object') return { ok: false, reason: 'pattern is not an object' };
407	  if (!PATTERN_KINDS.includes(pattern.kind)) return { ok: false, reason: 'unknown pattern kind ' + JSON.stringify(pattern.kind) };
408	  if (pattern.kind === 'anchored-regex') return anchoredRegexOk(pattern.value);
409	  if (pattern.kind === 'token-set') return tokenSetOk(pattern.value);
410	  return urlPathOk(pattern.value);
411	}
412	
413	function anchoredRegexOk(value) {
414	  if (typeof value !== 'string' || !value.length) return { ok: false, reason: 'anchored-regex value must be a non-empty string' };
415	  if (!/\\b|\^|\$/.test(value)) return { ok: false, reason: 'anchored-regex is not anchored (no \\b, ^ or $): a bare pattern substring-matches (C-019/C-059)' };
416	  try {
417	    new RegExp(value, 'i');
418	  } catch (err) {
419	    // FAIL-OPEN: the error is RECORDED verbatim in the returned reason; validateSpec surfaces it (C-050).
420	    return { ok: false, reason: 'anchored-regex does not compile (C-050): ' + err.message };
421	  }
422	  return { ok: true, reason: null };
423	}
424	
425	function tokenSetOk(value) {
426	  const tokens = value && Array.isArray(value.tokens) ? value.tokens : null;
427	  if (!tokens || !tokens.length) return { ok: false, reason: 'token-set has no tokens' };
428	  if (value.mode !== 'all' && value.mode !== 'any') return { ok: false, reason: 'token-set mode must be "all" or "any"' };
429	  for (const t of tokens) {
430	    if (typeof t !== 'string' || t.length < MIN_TOKEN_LEN) return { ok: false, reason: 'token ' + JSON.stringify(t) + ' is shorter than the ' + MIN_TOKEN_LEN + '-char floor (a bare short token substring-matches, C-059)' };
431	    if (!/[a-z0-9]/i.test(t)) return { ok: false, reason: 'token ' + JSON.stringify(t) + ' has no word character' };
432	  }
433	  return { ok: true, reason: null };
434	}
435	
436	function urlPathOk(value) {
437	  if (typeof value !== 'string' || value[0] !== '/') return { ok: false, reason: 'url-path must be a rooted path segment ("/xxx"), never a bare word (C-044)' };
438	  if (!/^\/[a-z0-9][a-z0-9/-]*$/i.test(value)) return { ok: false, reason: 'url-path ' + JSON.stringify(value) + ' is not a clean path segment' };
439	  return { ok: true, reason: null };
440	}
441	
442	// validateSpec(spec) -> { valid, errors }. Shape gate + the anchoring gate on every pattern. A
443	// register/behavioural spec must carry page_class null (the crawl never gates a non-crawl lane); a
444	// presence/absence spec must carry a page_class string. Any bad pattern makes the whole spec invalid.
445	function validateSpec(spec) {
446	  const errors = [];
447	  if (!spec || typeof spec !== 'object') return { valid: false, errors: ['spec is not an object'] };
448	  if (typeof spec.record_id !== 'string' || !spec.record_id) errors.push('record_id must be a non-empty string');
449	  if (!Number.isInteger(spec.duty_idx) || spec.duty_idx < 0) errors.push('duty_idx must be a non-negative integer');
450	  if (!EVIDENCE_TYPES.includes(spec.evidence_type)) errors.push('evidence_type ' + JSON.stringify(spec.evidence_type) + ' is not one of ' + EVIDENCE_TYPES.join('/'));
451	  if (!SURFACES.includes(spec.surface)) errors.push('surface ' + JSON.stringify(spec.surface) + ' is not one of ' + SURFACES.join('/'));
452	  validatePageClass(spec, errors);
453	  validatePatterns(spec, errors);
454	  return { valid: errors.length === 0, errors };
455	}
456	
457	function validatePageClass(spec, errors) {
458	  const laneOnly = spec.evidence_type === 'register' || spec.evidence_type === 'behavioural';
459	  if (laneOnly && spec.page_class !== null) errors.push('a ' + spec.evidence_type + ' spec must have page_class null (its evidence is a non-crawl lane)');
460	  if (!laneOnly && typeof spec.page_class !== 'string') errors.push('a ' + spec.evidence_type + ' spec must declare a page_class string');
461	}
462	
463	function validatePatterns(spec, errors) {
464	  if (!Array.isArray(spec.patterns)) { errors.push('patterns must be an array'); return; }
465	  for (let i = 0; i < spec.patterns.length; i++) {
466	    const p = spec.patterns[i];
467	    if (typeof p.negation_guarded !== 'boolean') errors.push('patterns[' + i + '].negation_guarded must be a boolean');
468	    const v = isAnchoredPatternValue(p);
469	    if (!v.ok) errors.push('patterns[' + i + '] rejected: ' + v.reason);
470	  }
471	}
472	
473	module.exports = {
474	  EVIDENCE_TYPES,
475	  SURFACES,
476	  PATTERN_KINDS,
477	  MIN_TOKEN_LEN,
478	  // compilation
479	  compileCatalogue,
480	  compileRecordSpecs,
481	  specForObligation,
482	  patternsFromElement,
483	  pageClassFor,
484	  surfaceFor,
485	  salientTokens,
486	  quotedSpans,
487	  // anchoring primitives + matcher helpers (one door, shared with propose.js so no second matcher drifts)
488	  anchorToken,
489	  buildAnchoredRegex,
490	  compileRegex,
491	  NEGATION_RX,
492	  isNegated,
493	  looksLikeReview,
494	  splitSentences,
495	  isProse,
496	  // validation
497	  validateSpec,
498	  isAnchoredPatternValue,
499	};
