79	// validateClassIdentifiers(taxonomy) -> violations[] for missing/duplicate class ids. Run BEFORE the
80	// known/byClass Set+Map are built: those collapse duplicate keys silently, so two conflicting rows
81	// for one class would both validate while defects bind only to the last (one door per class). The
82	// normalisation (String, trimmed) matches the per-row cls value used elsewhere.
83	function validateClassIdentifiers(taxonomy) {
84	  const violations = [];
85	  const seen = new Set();
86	  for (const t of taxonomy) {
87	    const raw = t && t.class;
88	    const cls = typeof raw === 'string' ? raw.trim() : '';
89	    if (!cls) {
90	      violations.push({ class: '(unnamed)', kind: 'no-class', detail: 'a taxonomy row has a missing or empty class identifier; every row must name exactly one class.' });
91	      continue;
92	    }
93	    if (seen.has(cls)) {
94	      violations.push({ class: cls, kind: 'duplicate-class', detail: 'class "' + cls + '" appears in more than one taxonomy row; class identifiers must be unique (one door per class), or a conflicting row is silently dropped by the lookup map.' });
95	    }
96	    seen.add(cls);
97	  }
98	  return violations;
99	}
100	
101	// classifyGuardedRow / classifyGapRow / validateTaxonomyRow -> the per-row rule engine, each owning
102	// one nesting-inducing branch so no single function exceeds the health caps.
103	function classifyGuardedRow(cls, gate, gateExists) {
104	  if (gateExists(gate)) return null; // rule 2 satisfied
105	  return { class: cls, kind: 'guarded-gate-missing', detail: 'status=guarded but catching_gate "' + gate + '" does not exist. A class claiming live protection must point at a real file; a deleted or mistyped gate is a false claim of coverage.' };
106	}
107	
108	// classifyGapRow(row, gateExists, deferred) where row = { cls, gate, t }. Bundled into one row object
109	// so the signature stays within the argument cap (CR round-4: <=4 formal parameters).
110	function classifyGapRow(row, gateExists, deferred) {
111	  const { cls, gate, t } = row;
