171	// validate(doc, gateExists) -> { violations, guarded, gap, deferred }
172	// Pure over its inputs (Constitution: pure functions over explicit inputs). Never reads argv,
173	// never exits; the CLI wrapper decides exit codes.
174	function validate(doc, gateExists) {
175	  const taxonomy = Array.isArray(doc && doc.taxonomy) ? doc.taxonomy : null;
176	  if (!taxonomy) {
177	    return { violations: [{ class: '(document)', kind: 'no-taxonomy', detail: 'crossref.json has no taxonomy array; nothing can be validated.' }], guarded: 0, gap: 0, deferred: [] };
178	  }
179	
180	  const violations = validateClassIdentifiers(taxonomy);
181	  const { known, byClass } = indexTaxonomy(taxonomy);
182	  const counters = { guarded: 0, gap: 0 };
183	  const deferred = []; // gap classes correctly awaiting a future phase (reported, not failed)
184	
185	  for (const t of taxonomy) {
186	    const v = validateTaxonomyRow(t, gateExists, counters, deferred);
187	    if (v) violations.push(v);
188	  }
189	  violations.push(...validateDefects(Array.isArray(doc.defects) ? doc.defects : [], known, byClass));
