1	'use strict';
2	// evidence/registers/lib/notes.js — the shared notes[] entry shape every register module in this
3	// directory uses when a field is absent (C-041 doctrine, ported from the browser evidence lane's own
4	// rule in docs/P3-ACCEPTANCE.md: a missing evidence-lane dependency is logged loudly and recorded,
5	// never silently skipped). `kind` is one of:
6	//   'skipped'  — a register was correctly judged not applicable (e.g. SRA on a hospitality site);
7	//                this is a budget decision (Rule 8), not a gap.
8	//   'degraded' — a register SHOULD have been checked but could not be: a missing key/config, a fetch
9	//                error, or a timeout. This is the founder-blocked / infra-gap class.
10	//   'no_match' — the register answered but no candidate cleared the name-match threshold (C-004), or
11	//                answered with zero candidates at all.
12	
13	function makeNote(register, kind, reason, detail, log) {
14	  const note = { register, kind, reason, detail: detail || null };
15	  if (typeof log === 'function') {
16	    try {
17	      log({ level: 'warn', source: 'evidence/registers', ...note });
18	    } catch (_err) {
19	      // FAIL-OPEN: an injected logger throwing must never break the lookup itself. The note object
20	      // returned to the caller (and pushed onto bundle.notes[]) IS the durable record of this event;
21	      // the logger call above is a best-effort side channel on top of it, not the record itself.
22	    }
23	  }
24	  return note;
25	}
26	
27	module.exports = { makeNote };
