215	// Two checker dialects are accepted:
216	//   a) stdout dialect: `--calibrate` prints {"checker":"...","findings":[...]} to stdout, exit 0.
217	//   b) gate-cli dialect (tools/lib/gate-cli.js): `--calibrate --json <path>` writes a findings
218	//      ARRAY to <path>, prints human text to stdout, and exits 1 when zero violations were
219	//      found. A non-zero exit is therefore NOT a runner error here: we still read the JSON
220	//      file and let this runner judge the (possibly empty) findings list.
221	// runCalibrateProcess(checkerPath, jsonOut) -> stdout from spawning the checker's --calibrate
222	// contract, having already validated its exit status against the two runner-judged states.
223	// The --calibrate contract has exactly two runner-judged statuses: 0 (checker found violations) and
224	// 1 (checker found ZERO on its fixtures - the caller then FAILs that calibration from the empty
225	// findings list). Exit 2 means the checker's OWN self-test failed: it is a broken tool and can
226	// NEVER earn a PASS, no matter what findings it managed to write. A broken self-test masked by
227	// parsed findings is the unearned-zero disease (Constitution Rule 4), so reject it unconditionally.
228	function runCalibrateProcess(checkerPath, jsonOut) {
229	  let stdout = '';
230	  let status = 0;
231	  try {
232	    stdout = execFileSync(process.execPath, [checkerPath, '--calibrate', '--json', jsonOut], {
233	      cwd: REPO_ROOT,
234	      encoding: 'utf8',
235	      timeout: 120000,
236	    });
237	  } catch (e) {
238	    // gate-cli exits 1 on zero calibration findings and 2 on a failed self-test. Keep the
239	    // stdout we got; if the checker wrote no JSON file either, the throw below reports it.
240	    stdout = (e.stdout || '') + '';
241	    status = (typeof e.status === 'number') ? e.status : 2;
242	  }
243	  if (status === 2) {
244	    throw new Error('checker self-test FAILED (exit 2): it cannot see the class it exists to catch, so its calibration result is void and cannot be masked by any parsed findings');
245	  }
246	  if (status !== 0 && status !== 1) {
247	    throw new Error('checker exited with undocumented --calibrate status ' + status + ' (expected 0 = findings, 1 = zero-findings, 2 = broken self-test)');
248	  }
249	  return stdout;
250	}
