252	// safeJsonParse(text) -> the parsed JSON value, or null when `text` is not valid JSON. Used for
253	// the stdout dialect: a non-JSON stdout just means the checker uses the file dialect instead.
254	function safeJsonParse(text) {
255	  try {
256	    return JSON.parse(text);
257	  } catch (e) {
258	    return null; // FAIL-OPEN: non-JSON stdout just means the checker uses the file dialect; handled by the caller.
259	  }
