270	function runExternalChecker(checkerPath) {
271	  const jsonOut = path.join(fs.mkdtempSync(path.join(os.tmpdir(), 'calibrate-')), 'findings.json');
272	  const stdout = runCalibrateProcess(checkerPath, jsonOut);
273	  if (fs.existsSync(jsonOut)) {
274	    const fromFile = findingsFromParsed(JSON.parse(fs.readFileSync(jsonOut, 'utf8')));
275	    if (fromFile) return fromFile;
276	  }
277	  const fromStdout = findingsFromParsed(safeJsonParse(stdout));
278	  if (fromStdout) return fromStdout;
279	  throw new Error('checker emitted neither {findings:[]} JSON on stdout nor a findings JSON file via --json');
280	}
