289	// checkMissingFixtures(cal, fixtureAbs) -> {entries, failed, skipped: 0}. entries is non-empty
290	// only when at least one of this calibration's fixture files does not exist on disk.
291	function checkMissingFixtures(cal, fixtureAbs) {
292	  const entries = [];
293	  let failed = 0;
294	  for (const f of fixtureAbs) {
295	    if (!fs.existsSync(f)) {
296	      entries.push({ name: cal.name, status: 'FAIL', detail: `fixture missing: ${f}` });
297	      failed++;
298	    }
299	  }
300	  return { entries, failed, skipped: 0 };
301	}
