303	// runInternalCalibration(cal, fixtureAbs) -> {entries, failed, skipped: 0}. The "internal": true
304	// calibration (payload-contract) runs payload/contract's validatePayload() directly rather than
305	// spawning an external checker.
306	function runInternalCalibration(cal, fixtureAbs) {
307	  const entries = [];
308	  let failed = 0;
309	  try {
310	    const findings = runInternalPayloadContract(fixtureAbs[0]);
311	    if (findings.length > 0) {
312	      entries.push({ name: cal.name, status: 'PASS', detail: `${findings.length} finding(s) on the fixture (e.g. ${findings[0].message})` });
313	    } else {
314	      entries.push({ name: cal.name, status: 'FAIL', detail: 'validatePayload() returned an EMPTY missing list on a deliberately incomplete payload - the contract gate is broken' });
315	      failed++;
316	    }
317	  } catch (e) {
318	    entries.push({ name: cal.name, status: 'FAIL', detail: `internal check errored: ${e.message}` });
319	    failed++;
320	  }
321	  return { entries, failed, skipped: 0 };
322	}
323	
324	// missingCheckerResult(cal, strict) -> the {entries,failed,skipped} result when no checker under
325	// tools/ was found for this calibration: FAIL in --strict mode (a fixture without a live checker
326	// is an unearned zero), SKIPPED otherwise (tools/ agent has not landed this gate yet).
327	function missingCheckerResult(cal, strict) {
328	  const detail = `no checker found (looked at: ${cal.checkerCandidates.join(', ')})`;
329	  if (strict) {
330	    return { entries: [{ name: cal.name, status: 'FAIL', detail: `${detail} - strict mode: a fixture without a live checker is an unearned zero` }], failed: 1, skipped: 0 };
331	  }
332	  return { entries: [{ name: cal.name, status: 'SKIPPED', detail: `${detail} - tools/ agent has not landed this gate yet; CI must flip to --strict when it does` }], failed: 0, skipped: 1 };
333	}
