335	// judgeCheckerFindings(cal, checker) -> {entries, failed} from running the checker and confirming
336	// EVERY fixture listed for this calibration was caught (CR-38: a multi-fixture calibration
337	// previously passed as long as ONE fixture produced a finding, so a checker could keep catching an
338	// old fixture while missing a new one).
339	function judgeCheckerFindings(cal, checker) {
340	  const findings = runExternalChecker(checker);
341	  const missingFixtures = cal.fixtures.filter((fx) => !findings.some((fd) => String(fd.file || '').includes(fx)));
342	  const fixtureHits = findings.filter((fd) => cal.fixtures.some((fx) => String(fd.file || '').includes(fx)));
343	  if (missingFixtures.length === 0) {
344	    return { entries: [{ name: cal.name, status: 'PASS', detail: `${fixtureHits.length} finding(s) across all ${cal.fixtures.length} fixture(s) via ${path.relative(REPO_ROOT, checker)}` }], failed: 0 };
345	  }
346	  return { entries: [{ name: cal.name, status: 'FAIL', detail: `${path.relative(REPO_ROOT, checker)} reported ZERO findings on: ${missingFixtures.join(', ')} - it has not earned its zero on every seeded fixture (${cal.description})` }], failed: 1 };
347	}
348	
349	// runExternalCalibration(cal, strict) -> {entries, failed, skipped}. Locates the checker under
350	// tools/ via findChecker(), reports SKIPPED (or FAIL in --strict mode) if none is found yet, and
351	// otherwise runs its --calibrate contract via runExternalChecker() and checks every listed
352	// fixture was caught. Behaviour is unchanged from the original inline version: failed/skipped are
353	// still exactly 0 or 1 per call (missingCheckerResult and judgeCheckerFindings each push exactly
354	// one entry and increment their own counter by at most 1).
355	function runExternalCalibration(cal, strict) {
356	  const checker = findChecker(cal.checkerCandidates);
357	  if (!checker) return missingCheckerResult(cal, strict);
358	  try {
359	    const { entries, failed } = judgeCheckerFindings(cal, checker);
360	    return { entries, failed, skipped: 0 };
361	  } catch (e) {
362	    return { entries: [{ name: cal.name, status: 'FAIL', detail: `checker errored or broke the --calibrate contract: ${e.message}` }], failed: 1, skipped: 0 };
363	  }
364	}
365	
366	// runOneCalibration(cal, strict) -> {entries: [...], failed: N, skipped: N} for one CALIBRATIONS
367	// entry. Semantics are UNCHANGED from the original inline loop body (do not change the
368	// CALIBRATIONS registry semantics or --strict behaviour): missing fixture files short-circuit
369	// straight to a FAIL entry per file; otherwise an "internal" calibration runs payload/contract
370	// directly and everything else runs its checker's --calibrate contract. The original loop tested
371	// `results.some((r) => r.name === cal.name && r.status === 'FAIL')` against the GLOBAL results
372	// list; since every entry pushed for earlier calibrations carries a DIFFERENT cal.name, that was
373	// already equivalent to testing only the entries just pushed for THIS calibration, which is what
374	// checkMissingFixtures's own (per-calibration) entries list does directly.
375	function runOneCalibration(cal, strict) {
376	  const fixtureAbs = cal.fixtures.map((f) => path.join(FIXTURES_DIR, f));
377	  const missing = checkMissingFixtures(cal, fixtureAbs);
378	  if (missing.entries.length > 0) return missing;
379	  if (cal.internal) return runInternalCalibration(cal, fixtureAbs);
380	  return runExternalCalibration(cal, strict);
381	}
382	
383	// report({strict, results, failed, skipped, asJson}) -> prints the run's summary in --json or
384	// human form, unchanged from the original inline block in main() (params bundled into one object;
385	// not exported, so the call site below is the only caller to update).
386	function report({ strict, results, failed, skipped, asJson }) {
387	  if (asJson) {
388	    console.log(JSON.stringify({ strict, results, failed, skipped }, null, 2));
389	    return;
390	  }
391	  console.log('calibration-known-bad: the earn-your-zero gate');
392	  for (const r of results) console.log(`  ${r.status.padEnd(7)} ${r.name}: ${r.detail}`);
393	  if (failed > 0) {
394	    console.log(`RESULT: FAIL - ${failed} gate(s) did not catch their seeded known-bad fixture. A gate that misses planted disease is reporting worthless greens.`);
395	  } else if (skipped > 0) {
396	    console.log(`RESULT: OK with ${skipped} SKIPPED - external checkers not landed yet. Flip CI to --strict once tools/ lands.`);
397	  } else {
398	    console.log('RESULT: OK - every gate caught its fixture.');
399	  }
400	}
401	
402	function main(argv) {
403	  const args = argv.slice(2);
404	  const strict = args.includes('--strict');
405	  const asJson = args.includes('--json');
406	  const unknown = args.filter((a) => !['--strict', '--json'].includes(a));
407	  if (unknown.length) {
408	    console.error(`Unknown argument(s): ${unknown.join(', ')}`);
409	    return 2;
410	  }
411	
412	  const results = [];
413	  let failed = 0;
414	  let skipped = 0;
415	
416	  for (const cal of CALIBRATIONS) {
417	    const r = runOneCalibration(cal, strict);
418	    results.push(...r.entries);
419	    failed += r.failed;
420	    skipped += r.skipped;
421	  }
422	
423	  report({ strict, results, failed, skipped, asJson });
424	  return failed > 0 ? 1 : 0;
425	}
426	
427	if (require.main === module) {
428	  process.exit(main(process.argv));
429	}
430	
431	module.exports = { CALIBRATIONS, runExternalChecker };
