1	#!/usr/bin/env node
2	'use strict';
3	/**
4	 * build-crossref.js - regenerate docs/failure-ledger/crossref.json from the primary sources.
5	 *
6	 * Sources (read fully, never invented):
7	 *   - the normalised sweep findings (256 deduped clusters + 6 ACT), passed as --sweep <path>
8	 *   - tools/history-regression/taxonomy.js (the derived class table, DG-01..DG-05, F-0001..F-0090)
9	 *
10	 * Output: an array of defect entries plus the class-level taxonomy rollup that check.js validates.
11	 * Each defect entry carries {class, caution_pointer, catching_gate, status} exactly as the task
12	 * asks, where catching_gate and status are inherited from the defect's class in taxonomy.js (one
13	 * door per class: the class decides the gate, the defect points at the class).
14	 *
15	 * The sweep defects are classified by (category -> class) with a message-keyword refinement for
16	 * the large "other" bucket. The mapping is deterministic and printed in --explain so a human can
17	 * audit every assignment; it is a best-effort triage of tool output, NOT a legal judgement - the
18	 * load-bearing contract is the class->gate mapping, which check.js enforces regardless of how any
19	 * single defect was triaged.
20	 *
21	 * Usage:
22	 *   node tools/history-regression/build-crossref.js --sweep <sweep-findings.json> [--out <path>]
23	 *   node tools/history-regression/build-crossref.js --sweep <path> --check   (build in memory,
24	 *                                                                              diff against the
25	 *                                                                              committed file)
26	 */
27	const fs = require('fs');
28	const path = require('path');
29	
30	const { TAXONOMY, DOMAIN_GATES, ACT } = require('./taxonomy');
31	
32	const ROOT = path.resolve(__dirname, '..', '..');
33	const DEFAULT_OUT = path.join(ROOT, 'docs', 'failure-ledger', 'crossref.json');
34	
35	const BY_CLASS = new Map(TAXONOMY.map((t) => [t.class, t]));
36	
37	// category -> class for the sweep buckets that map cleanly.
38	const CATEGORY_CLASS = {
39	  secret: 'secret-leak',
40	  injection: 'injection',
41	  duplication: 'duplication',
42	  'dead-code': 'dead-code',
43	  regex: 'unanchored-regex',
44	  'error-handling': 'silent-swallow',
45	  async: 'phantom-data',
46	  performance: 'budget-floor',
47	};
48	
49	// Message-keyword refinement for the "other" bucket, first match wins. Ordered most-specific
50	// first so a message mentioning both "version" and "cache" lands on cache-version, etc.
51	// A keyword is only a signal WITH semantic context (caution.md C-203): "out of scope" is not
52	// evidence of module-scope state, and a bare "market" wrongly matched "marketing", so those were
53	// tightened (\bmarkets?\b is the whole word, never the "marketing" prefix). Negative calibration
54	// cases in build-crossref.test.js lock both directions.
55	const KEYWORD_CLASS = [
56	  [/two doors|multiple producer|\bproducers\b|single producer|keep .* aligned|_n2c aligned/i, 'two-doors'],
57	  [/fail\s*closed|fail-open|before persist|before.*r2|persist.*payload|preflight|marked\s+`?ran`?|gates? (?:before|fail)|fail closed on neon/i, 'fail-open-gate'],
58	  [/module[- ]scope|singleton|_warn|_swarn|per-invocation|per-scan|reset between|scoped to one/i, 'module-scope-state'],
59	  [/bypass.*catalogue|truncated-code fallback|framework in rule identit|regulator|law name|law title|framework name|fw_name|placeholder string/i, 'law-fact-literal'],
60	  [/browser observation|presence rule type|prioritise browser|observed[- ]fact/i, 'absence-vs-observation'],
61	  [/persisted socials|bypass anchor|sharestoken|host anchoring|parse inputs before comparing|anchor.*scheme|url-substring/i, 'host-substring'],
62	  [/engine[- ]version|required_engine_version|scanner_cache|idem[_ ]key|replay|stale scan/i, 'cache-version'],
63	  [/jurisdicti|nexus|detectmarkets|\bbound\b|incorporated|established in|\bmarkets?\b/i, 'jurisdiction-nexus'],
64	  [/\bsector\b|classif/i, 'sector-misclassification'],
65	  [/fine|penalty|exposure|turnover|statutory (?:cap|max)|currency|\bband\b/i, 'exposure-error'],
66	  [/citation|provenance|official[- ]url|legislation\.gov|fetch.*200|repealed|duaa cap/i, 'provenance-fabrication'],
67	  [/polarity|prohibit|must[_ ]appear|advertis/i, 'polarity'],
68	  [/regex|pattern|escape|missing.?regexp.?anchor|hostname[- ]regexp/i, 'unanchored-regex'],
69	  [/file data in outbound|network data written|outbound network|http server|residential|object\.assign|user control data|sanitiz|xss|decode|escape.*inject|path[- ]?travers|shell[- ]?inject|child[- ]?process|\bhref\b/i, 'injection'],
70	  [/secret|rotate|webhook|credential/i, 'secret-leak'],
71	  [/mutable[- ]action|action[- ]tag|pin .* (?:commit )?sha|minimum[- ]release|renovate|dependabot|cooldown|dockerfile|node_tls|curl.*bash|npm ci|move zod|zod to|legacy sentry|sentry .* endpoint/i, 'ci-supply-chain'],
72	  [/contract|shared schema|payloadtod|defensive read|re-derive/i, 'contract-drift'],
73	  [/craftfix|renderer|hollow|filler/i, 'consistency-error'],
74	  [/quote|artifact|testimonial|hacked|injected spam|adjudicat|verdict|needs-review/i, 'breach-artifact'],
75	  [/node_modules|circular depend|aws-crypto/i, 'dead-code'],
76	  [/dead branch|never (?:match|call|execut)|unreachable|orphan|useless assignment|defensive code|trivial-conditional/i, 'dead-code'],
77	  [/coverage|absence|sitescanned|unfetched|corpus|crawl|\bspa\b|rendered/i, 'crawl-poverty'],
78	  [/done|phantom|on conflict|queue|reconcil|await.*ok|verifyauditurl|startup throw/i, 'phantom-data'],
79	  [/threshold|excluded_when|modern slavery|ccpa|residency/i, 'threshold-attachment'],
80	  [/deadline|timeout|promise\.race|hang|goto/i, 'deadline-hang'],
81	  [/duplicat|clone|copy-paste|jscpd/i, 'duplication'],
82	];
83	
84	function classifyOther(message) {
85	  const m = String(message || '');
86	  for (const [rx, cls] of KEYWORD_CLASS) if (rx.test(m)) return cls;
87	  return null; // no keyword claimed it
88	}
89	
90	// isOneDoorFinding(f) -> a one-door tool finding IS the two-doors class, whatever its prose says.
91	function isOneDoorFinding(f) {
92	  const tools = (f.tools || []).map((t) => String(t).toLowerCase());
93	  return tools.includes('one-door') || /^two doors/i.test(f.message || '');
94	}
95	
96	// hasCleanCategory(f) -> a non-"other" category bucket the tool already typed authoritatively
97	// (secret/injection/duplication/dead-code/regex/error-handling/async/performance); only "other" is ambiguous.
98	function hasCleanCategory(f) {
99	  return Boolean(f.category && f.category !== 'other' && CATEGORY_CLASS[f.category]);
100	}
101	
102	function classForSweep(f) {
103	  if (isOneDoorFinding(f)) return 'two-doors';
104	  if (hasCleanCategory(f)) return CATEGORY_CLASS[f.category];
105	  // The "other" bucket: keyword-refine the message, else fall to tooling-hygiene (tooling/test/CI
106	  // housekeeping or a genuinely diffuse lead - sweep-tool files, test gaps, workflow config; never dropped).
107	  const kw = classifyOther(f.message);
108	  if (kw) return kw;
109	  return 'tooling-hygiene';
110	}
111	
112	function entryFor(cls, extra) {
113	  const t = BY_CLASS.get(cls);
114	  if (!t) throw new Error('build-crossref: sweep defect classified as unknown class "' + cls + '" (a class with no taxonomy row is a bug in the classifier, not a silent pass).');
115	  return Object.assign({
116	    class: cls,
117	    caution_pointer: t.caution && t.caution.length ? t.caution[0] : 'NONE',
118	    catching_gate: t.catching_gate,
119	    status: t.status,
120	  }, extra);
121	}
122	
123	// assertValidClusterCount(sweep) -> the cluster-metadata gate, factored out. sweep.clusters is REQUIRED
124	// and must be a non-negative integer: a missing, non-numeric, negative or fractional cluster count is
125	// rejected (fail closed), NEVER treated as an optional check to skip. Line ~194 publishes sweep.clusters
126	// as the declared cluster count, so a malformed value must never reach the cross-reference at all.
127	function assertValidClusterCount(sweep) {
128	  if (!Number.isInteger(sweep.clusters) || sweep.clusters < 0) {
129	    throw new Error('build-crossref: sweep.clusters must be a non-negative integer (missing/non-numeric/negative/fractional cluster metadata fails closed, never optional-skip); got ' + JSON.stringify(sweep.clusters) + '.');
130	  }
131	  if (sweep.findings.length !== sweep.clusters) {
132	    throw new Error('build-crossref: sweep metadata is inconsistent - findings.length=' + sweep.findings.length
133	      + ' but metadata claims clusters=' + sweep.clusters + '. A truncated findings array must not produce a crossref asserting the original cluster count.');
134	  }
135	}
136	
137	// assertSweepConsistent(sweep) -> throws when the sweep JSON is truncated or its metadata disagrees
138	// with its findings. A truncated findings array must never silently produce a crossref that still
139	// claims the original cluster count (CR: reject inconsistent input before emitting the cross-ref).
140	function assertSweepConsistent(sweep) {
141	  if (!sweep || typeof sweep !== 'object') {
142	    throw new Error('build-crossref: sweep JSON is not an object.');
143	  }
144	  if (!Array.isArray(sweep.findings)) {
145	    throw new Error('build-crossref: sweep.findings is not an array; refusing to build a crossref from malformed sweep output.');
146	  }
147	  assertValidClusterCount(sweep);
148	}
149	
150	// collectDefects(sweep) -> the full defect list: the classified sweep clusters, the 5 domain-gate
151	// classes (engine-semantic defects no marketplace tool found), and the 6 ACT items (>=2 tools agree,
152	// recorded as their own entries so the ledger names them directly).
153	function sweepDefects(sweep) {
154	  return sweep.findings.map((f, i) => entryFor(classForSweep(f), {
155	    id: 'SW-' + String(i + 1).padStart(4, '0'),
156	    source: 'sweep',
157	    act: (f.corroboration || 0) >= 2,
158	    severity: f.severity,
159	    category: f.category,
160	    corroboration: f.corroboration || 0,
161	    tools: f.tools || [],
162	    path: f.path,
163	    message: f.message,
164	    fingerprint: f.fingerprint,
165	  }));
166	}
167	
168	function domainGateDefects() {
169	  return DOMAIN_GATES.map((dg) => entryFor(dg.class, {
170	    id: dg.id, source: 'domain-gate', act: true, severity: dg.past_severity,
171	    path: 'digest-findings-bible.md §12', message: dg.name + ': ' + dg.note,
172	  }));
173	}
174	
175	function actDefects() {
176	  return ACT.map((a) => entryFor(a.class, {
177	    id: a.id, source: 'act', act: true, severity: a.past_severity, path: a.path, message: a.note,
178	  }));
179	}
180	
181	function collectDefects(sweep) {
182	  return [...sweepDefects(sweep), ...domainGateDefects(), ...actDefects()];
183	}
184	
185	// buildTaxonomyRollup(defects) -> one row per class carrying the caution pointers it distils and its
186	// defect count. This is the structure check.js validates (catching_gate present and pointing at a
187	// real or phase-owned file).
188	function buildTaxonomyRollup(defects) {
189	  const counts = {};
190	  for (const d of defects) counts[d.class] = (counts[d.class] || 0) + 1;
191	  return TAXONOMY.map((t) => ({
192	    class: t.class,
193	    description: t.description,
194	    catching_gate: t.catching_gate,
195	    status: t.status,
196	    phase: t.phase,
197	    past_severity: t.past_severity,
198	    shipped_to_client: t.shipped,
199	    caution_pointers: t.caution,
200	    defect_count: counts[t.class] || 0,
201	  }));
202	}
203	
204	function build(sweepPath) {
205	  const sweep = JSON.parse(fs.readFileSync(sweepPath, 'utf8'));
206	  assertSweepConsistent(sweep);
207	
208	  const defects = collectDefects(sweep);
209	  const taxonomy = buildTaxonomyRollup(defects);
210	
211	  return {
212	    _README: 'The historical-failure crossref. Every distinct defect from the old estate mapped to a failure class, the caution.md pointer it distils, the gate in THIS repo that catches its class, and whether that gate is live (guarded) or planned (gap). Regenerate with: npm run history:build. Validated by: npm run history.',
213	    generated_at: new Date().toISOString().slice(0, 10),
214	    sources: [
215	      'sweep-findings.json (' + sweep.raw_findings + ' raw -> ' + sweep.after_dedupe + ' deduped -> ' + sweep.clusters + ' clusters, ' + sweep.act + ' ACT)',
216	      'docs/discovery/digest-findings-bible.md (§0 ACT, §12 domain gates, §13 dismissals)',
217	      'caution.md (C-001..C-202)',
218	      'CONSTITUTION.md (Part III gate map)',
219	    ],
220	    totals: {
221	      defects: defects.length,
222	      classes: taxonomy.length,
223	      guarded_classes: taxonomy.filter((t) => t.status === 'guarded').length,
224	      gap_classes: taxonomy.filter((t) => t.status === 'gap').length,
225	      act: defects.filter((d) => d.act).length,
226	    },
227	    classification_note: 'Sweep defects are triaged category->class with a message-keyword refinement for the "other" bucket (see build-crossref.js). This is best-effort triage of tool output; the load-bearing contract is the class->gate mapping, enforced by check.js.',
228	    taxonomy,
229	    defects,
230	  };
231	}
232	
233	// printExplain(doc) -> the --explain audit dump: one line per class with its status and defect count.
234	function printExplain(doc) {
235	  const byClass = {};
236	  for (const d of doc.defects) (byClass[d.class] = byClass[d.class] || []).push(d.id);
237	  for (const t of doc.taxonomy) console.log((t.status === 'gap' ? 'GAP  ' : 'guard') + ' ' + t.class.padEnd(26) + ' ' + String(t.defect_count).padStart(3) + '  ' + t.catching_gate);
238	}
239	
240	// runCheckMode(outPath, json, doc) -> --check: diff the freshly-built JSON against the committed file
241	// (ignoring generated_at) and exit 1 if stale, 0 if current. Never returns (always exits).
242	function runCheckMode(outPath, json, doc) {
243	  if (!fs.existsSync(outPath)) { console.error('crossref.json missing at ' + outPath); process.exit(1); }
244	  const current = fs.readFileSync(outPath, 'utf8');
245	  const norm = (s) => s.replace(/"generated_at":\s*"[^"]*"/, '"generated_at":"X"');
246	  if (norm(current) !== norm(json)) {
247	    console.error('crossref.json is STALE: rebuild with `npm run history:build`. The committed file does not match the sources.');
248	    process.exit(1);
249	  }
250	  console.log('crossref.json is up to date (' + doc.totals.defects + ' defects, ' + doc.totals.classes + ' classes).');
251	  process.exit(0);
252	}
253	
254	// writeCrossref(outPath, json, doc) -> write the built crossref to disk and report the totals.
255	function writeCrossref(outPath, json, doc) {
256	  fs.mkdirSync(path.dirname(outPath), { recursive: true });
257	  fs.writeFileSync(outPath, json);
258	  console.log('wrote ' + outPath + ': ' + doc.totals.defects + ' defects, ' + doc.totals.classes + ' classes (' + doc.totals.guarded_classes + ' guarded, ' + doc.totals.gap_classes + ' gap), ' + doc.totals.act + ' ACT.');
259	}
260	
261	function main() {
262	  const args = process.argv.slice(2);
263	  const sweepIdx = args.indexOf('--sweep');
264	  if (sweepIdx < 0) {
265	    console.error('usage: build-crossref.js --sweep <sweep-findings.json> [--out <path>] [--check] [--explain]');
266	    process.exit(2);
267	  }
268	  const outIdx = args.indexOf('--out');
269	  const outPath = outIdx >= 0 ? args[outIdx + 1] : DEFAULT_OUT;
270	  const doc = build(args[sweepIdx + 1]);
271	  const json = JSON.stringify(doc, null, 2) + '\n';
272	
273	  if (args.includes('--explain')) printExplain(doc);
274	  if (args.includes('--check')) runCheckMode(outPath, json, doc);
275	  writeCrossref(outPath, json, doc);
276	}
277	
278	if (require.main === module) main();
279	module.exports = { build, classForSweep, classifyOther, assertSweepConsistent };
