'use strict';
// evidence/crawler/coverage-contract.test.js - node:test for the coverage-as-blocking-data gate
// (caution.md C-029/C-044). Run: node --test evidence/crawler/coverage-contract.test.js
//
// This is the AUTOMATED CONSUMER for eval/calibration-known-bad/fixtures/p3-crawl-substring-classify.json
// (the C-044 seeded known-bad): before this test the fixture had no test driving it, so the anchored-
// path-token contract it seeds - classify() must NOT substring-credit 'cost'->pricing or 'feedback'->fees
// - was calibrated by nothing. Each trap URL must resolve to its `expect` class, never the `trap` class.

const test = require('node:test');
const assert = require('node:assert/strict');
const fs = require('fs');
const path = require('path');

const cc = require('./coverage-contract.js');

const FIXTURE = path.join(__dirname, '..', '..', 'eval', 'calibration-known-bad', 'fixtures', 'p3-crawl-substring-classify.json');

// ── the C-044 seeded known-bad: classify() anchors on whole path segments, never loose substrings ──
test('CALIBRATION (C-044): every fixture URL classifies to its expect class, never the trap class', () => {
  assert.ok(fs.existsSync(FIXTURE), 'the C-044 fixture must exist to calibrate this gate');
  const fx = JSON.parse(fs.readFileSync(FIXTURE, 'utf8'));
  assert.ok(Array.isArray(fx.cases) && fx.cases.length >= 1, 'the fixture must carry cases');
  let trapCases = 0;
  for (const c of fx.cases) {
    const got = cc.classify(c.url);
    assert.equal(got, c.expect, c.url + ' must classify as ' + c.expect + ', got ' + got);
    if (c.trap) {
      trapCases++;
      assert.notEqual(got, c.trap, c.url + ' must NEVER substring-credit the ' + c.trap + ' class (C-044)');
    }
  }
  assert.ok(trapCases >= 1, 'the fixture must seed at least one substring-trap URL, or it calibrates nothing');
});

// ── classify() basics ─────────────────────────────────────────────────────────────────────────────
test('classify anchors on path segments and defaults to other; the homepage is any empty/index path', () => {
  assert.equal(cc.classify('https://x.example/privacy-policy'), 'privacy');
  assert.equal(cc.classify('https://x.example/complaints'), 'complaints');
  assert.equal(cc.classify('https://x.example/'), 'homepage');
  assert.equal(cc.classify('https://x.example/index.html'), 'homepage');
  assert.equal(cc.classify('https://x.example/some-random-page'), 'other');
  // classify accepts a bare string, a {url} object and a {type} object (one door, tolerant input).
  assert.equal(cc.classify({ url: 'https://x.example/returns' }), 'returns');
});

// ── coverageFor(): per-rule covered|screened, the load-bearing blocking-data verdict ────────────────
function ruleNeeding(id, duty) {
  return { id, website_obligations: [{ evidence_type: 'presence', duty, elements: [] }] };
}

test('coverageFor: a rule is COVERED when its needed page-class was crawled, SCREENED when it was not', () => {
  const rules = [ruleNeeding('COMPLAINTS_RULE', 'publish the complaints procedure')];
  const withComplaints = [{ url: 'https://x.example/' }, { url: 'https://x.example/complaints' }];
  const withoutComplaints = [{ url: 'https://x.example/' }, { url: 'https://x.example/about' }];

  const covered = cc.coverageFor(rules, withComplaints, {});
  assert.equal(covered.rules.find((r) => r.id === 'COMPLAINTS_RULE').state, 'covered');
  assert.equal(covered.summary.screened, 0);

  const screened = cc.coverageFor(rules, withoutComplaints, {});
  const row = screened.rules.find((r) => r.id === 'COMPLAINTS_RULE');
  assert.equal(row.state, 'screened', 'an absence claim on an uncrawled page-class must be screened, never a breach (C-029)');
  assert.ok(/missing page-class "complaints"/.test(row.reason));
  assert.equal(screened.summary.screened, 1);
});

test('coverageFor: a register/behavioural (lane-only) rule is covered regardless of the crawl', () => {
  const laneRule = { id: 'REGISTER_RULE', website_obligations: [{ evidence_type: 'register', duty: 'appears on the register', elements: [] }] };
  const cov = cc.coverageFor([laneRule], [], {});
  const row = cov.rules.find((r) => r.id === 'REGISTER_RULE');
  assert.equal(row.state, 'covered');
  assert.match(row.reason, /non-crawl-evidence/);
});

test('coverageFor: the C-024 truncation interlock demotes an ABSENCE rule on a truncated corpus to screened', () => {
  const absenceRule = { id: 'PROHIBITION_RULE', website_obligations: [{ evidence_type: 'absence', duty: 'no prohibited privacy claim', elements: [] }] };
  const pages = [{ url: 'https://x.example/' }, { url: 'https://x.example/privacy' }];
  const notTruncated = cc.coverageFor([absenceRule], pages, { truncated: false });
  assert.equal(notTruncated.rules.find((r) => r.id === 'PROHIBITION_RULE').state, 'covered');
  const truncated = cc.coverageFor([absenceRule], pages, { truncated: true });
  const row = truncated.rules.find((r) => r.id === 'PROHIBITION_RULE');
  assert.equal(row.state, 'screened', 'a truncated corpus demotes an absence claim (C-024)');
  assert.match(row.reason, /truncated/i);
});

// ── pageClassForObligation() is the single door the breach proposer also imports ───────────────────
test('pageClassForObligation maps on-page duties by anchored tokens and is null for non-crawl lanes', () => {
  assert.equal(cc.pageClassForObligation({ evidence_type: 'presence', duty: 'publish the privacy notice', elements: [] }), 'privacy');
  assert.equal(cc.pageClassForObligation({ evidence_type: 'presence', duty: 'publish a general disclosure', elements: [] }), 'any');
  assert.equal(cc.pageClassForObligation({ evidence_type: 'register', duty: 'appears on the register', elements: [] }), null);
  assert.equal(cc.pageClassForObligation({ evidence_type: 'behavioural', duty: 'cookie consent obtained', elements: [] }), null);
});

test('isScreened is the hard-block predicate wave-2 reads to refuse a breach on unread content', () => {
  const rules = [ruleNeeding('COMPLAINTS_RULE', 'publish the complaints procedure')];
  const cov = cc.coverageFor(rules, [{ url: 'https://x.example/' }], {});
  assert.equal(cc.isScreened(cov, 'COMPLAINTS_RULE'), true);
  assert.equal(cc.isScreened(cov, 'NOT_A_RULE'), false);
});

