// tokenSetSource(value) -> a SINGLE-regex source for a token-set, or null when there is no linear-time
// single-regex form. 'any' compiles to a plain anchored alternation (linear). 'all' (co-occurrence,
// any order) has NO safe single-regex form: the old `(?=[\s\S]*t1)(?=[\s\S]*t2)...[\s\S]` construction
// backtracks catastrophically on real corpora (Rob P0: NY_RPC_7_3_7_4 hung, CA_RPC_CH7 / IL_RPC_7 ~6-8s)
// and a permutation alternation is exponential. So 'all' returns null and is matched token-by-token in
// matchesText() instead, which is guaranteed linear. No derived pattern ever contains an unbounded
// lookahead-dot-star again (validateSpec's ReDoS guard enforces this).
function tokenSetSource(value) {
  const tokens = value && Array.isArray(value.tokens) ? value.tokens : null;
  if (!tokens || !tokens.length) return null;
  if (value.mode === 'any') return '(?:' + tokens.map(anchorToken).join('|') + ')';
  return null; // 'all' co-occurrence is matched linearly in matchesText, never as a mega-regex
}

// tokenContains(text, token) -> is the single anchored token present in text. LINEAR: `\bword\b` is a
// literal with boundaries and has no backtracking blowup. A token that cannot compile matches nothing
// (fail-closed) and is surfaced by validateSpec (C-050), never silently swallowed.
function tokenContains(text, token) {
  let re;
  try { re = new RegExp(anchorToken(token), 'i'); }
  catch (_err) { return false; }
  return re.test(text);
}

// matchesText(pattern, text) -> does a pattern match `text`, in GUARANTEED LINEAR time. THE one text
// matcher propose.js calls (one door): a token-set is tested token by token (each `\bword\b` linear),
// combined by some() ('any') or every() ('all') - NEVER a co-occurrence mega-regex (the ReDoS Rob P0
// fixed). An anchored-regex is a `\b`-bounded word run joined by `\W+` (linear; the ReDoS guard blocks
// any dangerous form at validation). A url-path is matched by propose.js against page URLs, not here.
function matchesText(pattern, text) {
  if (!pattern || typeof pattern !== 'object') return false;
  const hay = String(text == null ? '' : text);
  if (pattern.kind === 'token-set') {
    const tokens = pattern.value && Array.isArray(pattern.value.tokens) ? pattern.value.tokens : [];
    if (!tokens.length) return false;
    const hit = (t) => tokenContains(hay, t);
    return pattern.value.mode === 'any' ? tokens.some(hit) : tokens.every(hit);
  }
  if (pattern.kind === 'anchored-regex') {
    const re = compileRegex(pattern);
    return re ? re.test(hay) : false;
  }
  return false;
}

